   140→/* =======================================================
   141→ *  In-Memory Inverted Index
   142→ *
   143→ *  Index Data Structure:
   144→ *      term -> { articleId -> termFrequency }
   145→ * ===================================================== */
   146→
   147→class InvertedIndex
   148→{
   149→public:
   150→    using PostingList      = std::unordered_map<ArticleId, std::uint32_t>;
   151→    using Container        = std::unordered_map<std::string, PostingList>;
   152→
   153→    std::vector<ArticleId> query(const std::string& term) const
   154→    {
   155→        std::shared_lock lock(m_mutex);
   156→        auto             it = m_index.find(term);
   157→        if (it == m_index.end()) return {};
   158→        std::vector<ArticleId> result;
   159→        result.reserve(it->second.size());
   160→        for (auto&& [aid, tf] : it->second) result.push_back(aid);
   161→        return result;
   162→    }
   163→
   164→    std::unordered_map<ArticleId, Score>
   165→    queryWithScore(const std::vector<std::string>& terms) const
   166→    {
   167→        std::shared_lock lock(m_mutex);
   168→        std::unordered_map<ArticleId, Score> scores;
   169→
   170→        for (const auto& term : terms)
   171→        {
   172→            auto it = m_index.find(term);
   173→            if (it == m_index.end()) continue;
   174→
   175→            double idf =
   176→                std::log(static_cast<double>(m_totalDocuments) /
   177→                         (1.0 + static_cast<double>(it->second.size())));
   178→
   179→            for (const auto& [aid, tf] : it->second)
   180→            {
   181→                scores[aid] += static_cast<double>(tf) * idf;
   182→            }
   183→        }
   184→        return scores;
   185→    }
   186→
   187→    void build(const std::vector<Article>& articles)
   188→    {
   189→        Container          newIndex;
   190→        std::uint64_t      docCount = articles.size();
   191→        std::vector<std::string> scratchTokenBuf;
   192→
   193→        for (const auto& article : articles)
   194→        {
   195→            scratchTokenBuf.clear();
   196→            tokenize(article, scratchTokenBuf);
   197→
   198→            std::unordered_map<std::string, std::uint32_t> termFreq;
   199→            for (const auto& tok : scratchTokenBuf) ++termFreq[tok];
   200→
   201→            for (const auto& [term, freq] : termFreq)
   202→                newIndex[term][article.id] = freq;
   203→        }
   204→
   205→        {
   206→            std::unique_lock lock(m_mutex);
   207→            m_index          = std::move(newIndex);
   208→            m_totalDocuments = docCount;
   209→        }
   210→    }
   211→
   212→private:
   213→    //  Very naive tokenizer – lowercases & splits on non-alnum.
   214→    static void tokenize(const Article& art, std::vector<std::string>& out)
   215→    {
   216→        std::string merged = art.title + " " + art.body;
   217→        std::string token;
   218→        token.reserve(32);
   219→
   220→        auto flushToken = [&]()
   221→        {
   222→            if (token.empty()) return;
   223→            std::transform(token.begin(), token.end(), token.begin(),
   224→                           [](unsigned char c) { return std::tolower(c); });
   225→
   226→            if (!StopWords::dictionary().count(token)) out.push_back(token);
   227→            token.clear();
   228→        };
   229→
   230→        for (char ch : merged)
   231→        {
   232→            if (std::isalnum(static_cast<unsigned char>(ch)))
   233→            {
   234→                token.push_back(ch);
   235→            }
   236→            else
   237→            {
   238→                flushToken();
   239→            }
   240→        }
   241→        flushToken();
   242→    }
   243→
   244→    Container                    m_index;
   245→    std::uint64_t                m_totalDocuments{0};
   246→    mutable std::shared_mutex    m_mutex;
   247→};
