   137→using JobHandle = std::function<void()>;
   138→
   139→/**
   140→ * Thread-safe in-memory job dispatcher that accepts lightweight tasks. In
   141→ * production the system uses a more sophisticated queue that can survive
   142→ * process restarts, but this implementation is suitable for runtime
   143→ * composition or testing.
   144→ */
   145→class JobDispatcher
   146→{
   147→public:
   148→    JobDispatcher()
   149→        : running_{true}, worker_{[this] { workerLoop(); }} {}
   150→
   151→    ~JobDispatcher()
   152→    {
   153→        {
   154→            std::unique_lock l{mutex_};
   155→            running_ = false;
   156→            cond_.notify_all();
   157→        }
   158→        if (worker_.joinable())
   159→            worker_.join();
   160→    }
   161→
   162→    void submit(JobHandle job)
   163→    {
   164→        {
   165→            std::unique_lock l{mutex_};
   166→            queue_.emplace(std::move(job));
   167→        }
   168→        cond_.notify_one();
   169→    }
   170→
   171→private:
   172→    void workerLoop()
   173→    {
   174→        while (true)
   175→        {
   176→            JobHandle job;
   177→            {
   178→                std::unique_lock l{mutex_};
   179→                cond_.wait(l, [this] { return !queue_.empty() || !running_; });
   180→
   181→                if (!running_ && queue_.empty())
   182→                    break;
   183→
   184→                job = std::move(queue_.front());
   185→                queue_.pop();
   186→            }
   187→
   188→            try
   189→            {
   190→                job();
   191→            }
   192→            catch (const std::exception &ex)
   193→            {
   194→                spdlog::error("[JobDispatcher] job failed: {}", ex.what());
   195→            }
   196→            catch (...)
   197→            {
   198→                spdlog::error("[JobDispatcher] job failed with unknown error");
   199→            }
   200→        }
   201→    }
   202→
   203→    std::atomic_bool         running_;
   204→    std::thread              worker_;
   205→    std::queue<JobHandle>    queue_;
   206→    std::mutex               mutex_;
   207→    std::condition_variable  cond_;
   208→};
