   218→/**
   219→ * Very naive HTML tag stripper. A real implementation would use a proper HTML
   220→ * parser (e.g., Gumbo) but this is sufficient for demonstration purposes.
   221→ */
   222→[[nodiscard]]
   223→std::string stripHtml(std::string_view input)
   224→{
   225→    std::string output;
   226→    output.reserve(input.size());
   227→
   228→    bool inTag = false;
   229→    for (char c : input)
   230→    {
   231→        if (c == '<')
   232→        {
   233→            inTag = true;
   234→            continue;
   235→        }
   236→        if (c == '>')
   237→        {
   238→            inTag = false;
   239→            continue;
   240→        }
   241→        if (!inTag)
   242→            output.push_back(c);
   243→    }
   244→
   245→    return output;
   246→}
