   248→/**
   249→ * Basic word tokenizer that lowercases and splits on whitespace / punctuation.
   250→ */
   251→[[nodiscard]]
   252→std::vector<std::string> tokenize(std::string_view text)
   253→{
   254→    std::vector<std::string> tokens;
   255→    std::string current;
   256→
   257→    auto flushToken = [&]() {
   258→        if (!current.empty())
   259→        {
   260→            std::transform(current.begin(), current.end(), current.begin(),
   261→                           [](unsigned char c) { return std::tolower(c); });
   262→            tokens.emplace_back(std::move(current));
   263→            current.clear();
   264→        }
   265→    };
   266→
   267→    for (char c : text)
   268→    {
   269→        if (std::isalnum(static_cast<unsigned char>(c)))
   270→        {
   271→            current.push_back(c);
   272→        }
   273→        else
   274→        {
   275→            flushToken();
   276→        }
   277→    }
   278→    flushToken();
   279→    return tokens;
   280→}
