   304→
   305→    /**
   306→     * Index or re-index a single article. If the article is not searchable, the
   307→     * previously indexed instance (if any) will be deleted.
   308→     */
   309→    void onArticleChanged(const domain::UUID &id)
   310→    {
   311→        dispatcher_->submit([self = shared_from_this(), id]() {
   312→            self->processArticleChange(id);
   313→        });
   314→    }
   315→
   316→    /**
   317→     * Remove an article from the search index (e.g., author deleted).
   318→     */
   319→    void onArticleDeleted(const domain::UUID &id)
   320→    {
   321→        dispatcher_->submit([self = shared_from_this(), id]() {
   322→            try
   323→            {
   324→                self->backend_->removeDocument(id);
   325→                spdlog::info("[SearchService] removed article {} from index", id);
   326→            }
   327→            catch (const std::exception &ex)
   328→            {
   329→                spdlog::error("[SearchService] failed to remove article {}: {}",
   330→                              id, ex.what());
   331→            }
   332→        });
   333→    }
   334→
   335→    /**
   336→     * Rebuild the complete index in batches. Long-running operation executed in
   337→     * the background and progress is reported through logging.
   338→     *
   339→     * @param pause Optional pause between batches to reduce DB load.
   340→     */
   341→    void rebuildIndex(std::optional<std::chrono::milliseconds> pause =
   342→                          std::chrono::milliseconds{50})
   343→    {
   344→        dispatcher_->submit([self = shared_from_this(), pause]() {
   345→            constexpr std::size_t kBatchSize = 256;
   346→            std::size_t           offset     = 0;
   347→            std::size_t           total      = 0;
   348→
   349→            spdlog::info("[SearchService] Starting full index rebuild");
   350→
   351→            while (true)
   352→            {
   353→                auto articles = self->repo_->fetchArticles(offset, kBatchSize);
   354→                if (articles.empty())
   355→                    break;
   356→
   357→                for (auto &article : articles)
   358→                {
   359→                    try
   360→                    {
   361→                        if (article.isSearchable())
   362→                            self->backend_->indexDocument(article);
   363→                        else
   364→                            self->backend_->removeDocument(article.id);
   365→                    }
   366→                    catch (const std::exception &ex)
   367→                    {
   368→                        spdlog::warn(
   369→                            "[SearchService] Skipping article {}: {}", article.id,
   370→                            ex.what());
   371→                    }
   372→                    ++total;
   373→                }
   374→
   375→                offset += articles.size();
   376→
   377→                if (pause && *pause > std::chrono::milliseconds::zero())
   378→                    std::this_thread::sleep_for(*pause);
   379→            }
   380→            spdlog::info("[SearchService] Rebuild finished. {} articles processed.",
   381→                         total);
   382→        });
   383→    }
   384→
   385→private:
   386→    void processArticleChange(const domain::UUID &id)
   387→    {
   388→        auto optArticle = repo_->findById(id);
   389→        if (!optArticle)
   390→        {
   391→            spdlog::warn("[SearchService] article {} not found, deleting from index",
   392→                         id);
   393→            backend_->removeDocument(id);
