    44→class IUserRepository
    45→{
    46→public:
    47→    virtual ~IUserRepository() = default;
    48→
    49→    // Returns true if a user with the supplied e-mail exists and is active.
    50→    virtual bool doesUserExist(std::string_view email) const = 0;
    51→
    52→    // Updates the user’s password hash with a pre-hashed value.
    53→    virtual void updatePassword(std::string_view email,
    54→                                std::string_view passwordHash) = 0;
    55→};
    56→
    57→class IPasswordResetRepository
    58→{
    59→public:
    60→    struct TokenRecord
    61→    {
    62→        std::string email;
    63→        std::chrono::system_clock::time_point expiresAt;
    64→    };
    65→
    66→    virtual ~IPasswordResetRepository() = default;
    67→
    68→    // Persists token → (email, expiry).  Overwrite if already present.
    69→    virtual void upsertToken(std::string_view token, TokenRecord record)     = 0;
    70→
    71→    // Removes token from the store.  No-op if token is unknown.
    72→    virtual void removeToken(std::string_view token)                         = 0;
    73→
