   116→class PasswordResetService final
   117→{
   118→public:
   119→    struct Config
   120→    {
   121→        std::chrono::minutes tokenLifetime      = 60min;
   122→        std::chrono::minutes cooldownPerEmail   = 5min;
   123→        std::size_t          maxTokensPerHour   = 5;
   124→        std::string          frontendResetPath  = "/auth/password-reset/";
   125→        std::string          resetEmailSubject  = "Reset your BlogSuite password";
   126→    };
   127→
   128→    PasswordResetService(IUserRepository& userRepo,
   129→                         IPasswordResetRepository& tokenRepo,
   130→                         IEmailDispatcher& emailer,
   131→                         Config cfg = {})
   132→        : m_userRepo{userRepo}
   133→        , m_tokenRepo{tokenRepo}
   134→        , m_emailDispatcher{emailer}
   135→        , m_cfg{std::move(cfg)}
   136→    {}
   137→
   138→    // Public API ----------------------------------------------------------------
   139→
   140→    // 1. Initiate Reset Request --------------------------------------------------
   141→    //    Throws RateLimitExceeded if the email has exhausted its quota.
   142→    void requestPasswordReset(std::string_view email)
   143→    {
   144→        validateEmail(email);
   145→
   146→        auto now = std::chrono::system_clock::now();
   147→
   148→        {
   149→            std::scoped_lock lk{m_rateMutex};
   150→
   151→            pruneRateLog(now);
   152→            auto& info = m_rateLog[email];
   153→            if (info.count >= m_cfg.maxTokensPerHour)
   154→                throw RateLimitExceeded{"Too many password-reset requests."};
   155→
   156→            if (now - info.lastRequest < m_cfg.cooldownPerEmail)
   157→                throw RateLimitExceeded{"Password-reset requests are cooling down."};
   158→
   159→            ++info.count;
   160→            info.lastRequest = now;
   161→        }
   162→
   163→        // Generate a secure, unique token.
   164→        const auto token = generateToken();
   165→
   166→        // Persist token with its expiry.
   167→        m_tokenRepo.upsertToken(token, {
   168→            std::string{email},
   169→            now + m_cfg.tokenLifetime
   170→        });
   171→
   172→        // Build reset URL (assumes host rendered on frontend).
   173→        std::ostringstream url;
   174→        url << m_cfg.frontendResetPath << token;
   175→
   176→        // Send e-mail through dispatcher (async).
   177→        m_emailDispatcher.enqueueResetEmail(email, url.str());
   178→    }
   179→
   180→    // 2. Reset Password ----------------------------------------------------------
   181→    //    Validates token, updates password hash, and consumes token.
   182→    void resetPassword(std::string_view token, std::string_view newPasswordHash)
   183→    {
   184→        auto now = std::chrono::system_clock::now();
   185→
   186→        auto record = m_tokenRepo.findToken(token);
   187→        if (!record)
   188→            throw TokenInvalid{"Password-reset token invalid."};
   189→
   190→        if (now > record->expiresAt)
   191→        {
   192→            m_tokenRepo.removeToken(token);
   193→            throw TokenExpired{"Password-reset token expired."};
   194→        }
   195→
   196→        // Update password — if user is deleted / disabled this will throw from repo.
   197→        m_userRepo.updatePassword(record->email, newPasswordHash);
   198→
   199→        // Consume token.
   200→        m_tokenRepo.removeToken(token);
   201→    }
   202→
   203→    // 3. Validate Token (for UI feedback) ----------------------------------------
   204→    bool isTokenValid(std::string_view token) const
   205→    {
   206→        auto now = std::chrono::system_clock::now();
   207→        auto record = m_tokenRepo.findToken(token);
   208→
   209→        return record && now <= record->expiresAt;
   210→    }
   211→
   212→private:
   213→    // Internal helpers -----------------------------------------------------------
   214→
   215→    static void validateEmail(std::string_view email)
   216→    {
   217→        if (email.empty() || email.size() > 320 || email.find('@') == std::string::npos)
   218→            throw PasswordResetException{"Invalid e-mail supplied."};
   219→    }
   220→
   221→    // Generates a cryptographically secure, 128-bit token encoded in base62.
   222→    static std::string generateToken()
   223→    {
   224→        constexpr char charset[] =
   225→            "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
   226→        constexpr std::size_t charsetSize = sizeof(charset) - 1;
   227→        constexpr std::size_t bytesNeeded = 16; // 128-bit
   228→        constexpr std::size_t outputLen   = (bytesNeeded * 8 + 5) / 6; // ceil
   229→
   230→        std::array<std::uint8_t, bytesNeeded> randomBytes{};
   231→
   232→        {
   233→            static thread_local std::random_device rd;
   234→            static thread_local std::mt19937_64 rng{rd()};
   235→            std::uniform_int_distribution<int> dist{0, 255};
   236→            for (auto& b : randomBytes) b = static_cast<std::uint8_t>(dist(rng));
   237→        }
   238→
   239→        // Convert to base62
   240→        std::string token;
   241→        token.reserve(outputLen);
   242→
   243→        std::uint64_t accumulator = 0;
   244→        int bits = 0;
   245→        for (std::uint8_t byte : randomBytes)
   246→        {
   247→            accumulator = (accumulator << 8) | byte;
   248→            bits += 8;
   249→            while (bits >= 6)
   250→            {
   251→                bits -= 6;
   252→                token.push_back(charset[(accumulator >> bits) & 0x3F]);
   253→            }
   254→        }
   255→        if (bits > 0)
   256→            token.push_back(charset[(accumulator << (6 - bits)) & 0x3F]);
   257→
   258→        return token;
   259→    }
