   261→    // Rate Limiting --------------------------------------------------------------
   262→
   263→    struct RateInfo
   264→    {
   265→        std::size_t                           count        = 0;
   266→        std::chrono::system_clock::time_point lastRequest  = std::chrono::system_clock::now();
   267→    };
   268→
   269→    void pruneRateLog(const std::chrono::system_clock::time_point& now)
   270→    {
   271→        for (auto it = m_rateLog.begin(); it != m_rateLog.end(); )
   272→        {
   273→            if (now - it->second.lastRequest > 1h)
   274→                it = m_rateLog.erase(it);
   275→            else
   276→                ++it;
   277→        }
   278→    }
   279→
