   116→
   117→    Limits userLimits_;
   118→    Limits ipLimits_;
   119→    orm::EntityManager& em_;       // Not owned
   120→
   121→    std::mutex mtx_;
   122→    std::unordered_map<std::string, CounterState> cache_;
   123→};
