   128→LoginAttemptThrottler::LoginAttemptThrottler(Limits userLimits,
   129→                                             Limits ipLimits,
   130→                                             orm::EntityManager& em)
   131→    : userLimits_{std::move(userLimits)}
   132→    , ipLimits_{std::move(ipLimits)}
   133→    , em_{em}
   134→{
   135→    // Pre-load existing counters (best-effort)
   136→    try {
   137→        auto rows = orm::QueryBuilder(em_)
   138→                        .select<LoginAttemptDTO>()
   139→                        .execute();
   140→
   141→        std::lock_guard lk{mtx_};
   142→        for (auto& row : rows) {
   143→            cache_[row.key] = CounterState{row.counter, row.windowStart,
   144→                                           row.lockedUntil, false};
   145→        }
   146→        util::Logger::info("LoginAttemptThrottler: Initialized with {} entries in cache",
   147→                           cache_.size());
   148→    } catch (const std::exception& ex) {
   149→        util::Logger::warn("LoginAttemptThrottler: Unable to preload counters – {}",
   150→                           ex.what());
   151→    }
   152→}
