   164→void LoginAttemptThrottler::assertNotLocked(const std::optional<std::uint64_t>& userId,
   165→                                            const std::string& ipAddress)
   166→{
   167→    const auto now = std::chrono::system_clock::now();
   168→
   169→    auto isLocked = [&](const std::string& key) {
   170→        std::lock_guard lk{mtx_};
   171→        const auto it = cache_.find(key);
   172→        return it != cache_.end() && it->second.lockedUntil > now;
   173→    };
   174→
   175→    if (userId && isLocked(makeUserKey(*userId))) {
   176→        throw ThrottlingException{"Too many failed log-in attempts (user locked)."};
   177→    }
   178→    if (isLocked(makeIpKey(ipAddress))) {
   179→        throw ThrottlingException{"Too many failed log-in attempts (IP locked)."};
   180→    }
   181→}
