   209→void LoginAttemptThrottler::registerFailure(const std::optional<std::uint64_t>& userId,
   210→                                            const std::string& ipAddress)
   211→{
   212→    try {
   213→        if (userId) {
   214→            touch(makeUserKey(*userId), userLimits_);
   215→        }
   216→        touch(makeIpKey(ipAddress), ipLimits_);
   217→    } catch (const std::exception& e) {
   218→        util::Logger::error("LoginAttemptThrottler.registerFailure: {}", e.what());
   219→    }
   220→}
   221→
   222→void LoginAttemptThrottler::registerSuccess(const std::optional<std::uint64_t>& userId,
   223→                                            const std::string& ipAddress)
   224→{
   225→    std::lock_guard lk{mtx_};
   226→
   227→    if (userId) {
   228→        cache_.erase(makeUserKey(*userId));
   229→    }
   230→    cache_.erase(makeIpKey(ipAddress));
   231→}
