   278→class ThrottlerFlushJob {
   279→public:
   280→    explicit ThrottlerFlushJob(LoginAttemptThrottler& throttler,
   281→                               std::chrono::minutes interval)
   282→        : throttler_{throttler}
   283→        , interval_{interval}
   284→        , worker_{&ThrottlerFlushJob::run, this}
   285→    {
   286→        worker_.detach();  // Fire-and-forget background thread
   287→    }
   288→
   289→private:
   290→    void run()
   291→    {
   292→        util::Logger::info("ThrottlerFlushJob: Worker thread started.");
   293→
   294→        while (true) {
   295→            std::this_thread::sleep_for(interval_);
   296→            throttler_.flushToDatabase();
   297→        }
   298→    }
   299→
   300→    LoginAttemptThrottler& throttler_;
   301→    std::chrono::minutes interval_;
   302→    std::thread worker_;
   303→};
