    50→class TokenBucket final
    51→{
    52→public:
    53→    TokenBucket(std::size_t maxTokens, double refillRatePerSec) noexcept
    54→        : _maxTokens(static_cast<double>(maxTokens))
    55→        , _refillRatePerSec(refillRatePerSec)
    56→        , _tokens(_maxTokens)
    57→        , _lastRefill(Clock::now())
    58→    {
    59→    }
    60→
    61→    TokenBucket(const TokenBucket&)            = delete;
    62→    TokenBucket& operator=(const TokenBucket&) = delete;
    63→    TokenBucket(TokenBucket&&)                 = default;
    64→    TokenBucket& operator=(TokenBucket&&)      = default;
    65→
    66→    /**
    67→     *  Attempt to remove one token from the bucket. Returns true if a token
    68→     *  was successfully consumed, false otherwise.
    69→     */
    70→    bool consume()
    71→    {
    72→        refill();
    73→
    74→        if (_tokens >= 1.0)
    75→        {
    76→            _tokens -= 1.0;
    77→            return true;
    78→        }
    79→        return false;
    80→    }
