   342→        // ------------------------------------------------------------------
   343→        // 3. Fire cross-cutting concerns outside the transaction
   344→        // ------------------------------------------------------------------
   345→        logAudit(actorUserId, post);
   346→        enqueueSideEffects(post);
   347→
   348→        spdlog::info("Post id={} published by actor={}", postId, actorUserId);
   349→    }
