   148→// -----------------------------------------------------------------------------
   149→// LRU Cache (thread-safe)
   150→// -----------------------------------------------------------------------------
   151→
   152→template <typename Key, typename Value, std::size_t Capacity = 128>
   153→class LruCache {
   154→public:
   155→    bool get(const Key& k, Value& out_value) {
   156→        std::shared_lock lock(mu_);
   157→        auto it = map_.find(k);
   158→        if (it == map_.end()) return false;
   159→        // Move touched item to front
   160→        {
   161→            std::unique_lock ulock(mu_, std::adopt_lock);
   162→            list_.splice(list_.begin(), list_, it->second);
   163→        }
   164→        out_value = it->second->second;
   165→        return true;
   166→    }
   167→
   168→    void put(const Key& k, Value v) {
   169→        std::unique_lock lock(mu_);
   170→        auto it = map_.find(k);
   171→        if (it != map_.end()) {
   172→            it->second->second = std::move(v);
   173→            list_.splice(list_.begin(), list_, it->second);
   174→            return;
   175→        }
   176→        if (list_.size() >= Capacity) {
   177→            auto last = list_.end();
   178→            --last;
   179→            map_.erase(last->first);
   180→            list_.pop_back();
   181→        }
   182→        list_.emplace_front(k, std::move(v));
   183→        map_[k] = list_.begin();
   184→    }
   185→
   186→private:
   187→    mutable std::shared_mutex
   188→        mu_;  // allows concurrent reads while writes are unique
   189→    std::list<std::pair<Key, Value>> list_;
   190→    std::unordered_map<Key, typename std::list<std::pair<Key, Value>>::iterator> map_;
   191→};
