   197→class QueryParser {
   198→public:
   199→    explicit QueryParser(std::string q)
   200→        : input_(std::move(q)), pos_(0) {
   201→        tokenize();
   202→    }
   203→
   204→    std::unique_ptr<QueryNode> parse() {
   205→        auto node = parse_or();
   206→        if (pos_token_ != tokens_.size()) {
   207→            throw ParseError("Unexpected token at end of query.");
   208→        }
   209→        return node;
   210→    }
   211→
   212→private:
   213→    enum class TokType { WORD, PHRASE, AND, OR, NOT, LPAREN, RPAREN };
   214→
   215→    struct Token {
   216→        TokType     type;
   217→        std::string text;  // For WORD/PHRASE
   218→    };
   219→
   220→    void tokenize() {
   221→        static const std::regex re(R"((\"[^\"]+\")|\(|\)|\bAND\b|\bOR\b|\bNOT\b|\S+)",
   222→                                   std::regex::icase);
   223→        std::smatch m;
   224→        std::string s = input_;
   225→        while (std::regex_search(s, m, re)) {
   226→            std::string tok = m.str(0);
   227→            if (tok == "(") { tokens_.push_back({TokType::LPAREN, tok}); }
   228→            else if (tok == ")") { tokens_.push_back({TokType::RPAREN, tok}); }
   229→            else if (icase_eq(tok, "AND")) { tokens_.push_back({TokType::AND, tok}); }
   230→            else if (icase_eq(tok, "OR")) { tokens_.push_back({TokType::OR, tok}); }
   231→            else if (icase_eq(tok, "NOT")) { tokens_.push_back({TokType::NOT, tok}); }
   232→            else if (tok.size() > 2 && tok.front() == '"' && tok.back() == '"') {
   233→                tokens_.push_back({TokType::PHRASE,
   234→                                   tok.substr(1, tok.size() - 2)});  // strip quotes
   235→            } else {
   236→                tokens_.push_back({TokType::WORD, tok});
   237→            }
   238→            s = m.suffix();
   239→        }
   240→    }
   241→
   242→    static bool icase_eq(const std::string& a, const std::string& b) {
   243→        return util::to_lower(a) == util::to_lower(b);
   244→    }
   245→
   246→    // Recursive-descent parser with operator precedence:
   247→    //  OR (lowest) -> AND -> NOT -> term/paren (highest)
   248→    std::unique_ptr<QueryNode> parse_or() {
   249→        auto left = parse_and();
   250→        while (match(TokType::OR)) {
   251→            auto right = parse_and();
   252→            std::vector<std::unique_ptr<QueryNode>> children;
   253→            children.push_back(std::move(left));
   254→            children.push_back(std::move(right));
   255→            left = QueryNode::make(NodeType::OR, std::move(children));
   256→        }
   257→        return left;
   258→    }
   259→
   260→    std::unique_ptr<QueryNode> parse_and() {
   261→        auto left = parse_not();
   262→        while (match(TokType::AND)) {
