   200→// Naive thread-pool dispatcher for background indexing jobs.
   201→class SimpleThreadPoolDispatcher final : public IJobDispatcher
   202→{
   203→public:
   204→    explicit SimpleThreadPoolDispatcher(std::size_t workers = std::thread::hardware_concurrency())
   205→        : _shutdown(false)
   206→    {
   207→        workers = std::max<std::size_t>(1, workers);
   208→        for (std::size_t i = 0; i < workers; ++i)
   209→            _threads.emplace_back([this] { workerLoop(); });
   210→    }
   211→
   212→    ~SimpleThreadPoolDispatcher() override
   213→    {
   214→        {
   215→            std::lock_guard lock(_mtx);
   216→            _shutdown = true;
   217→        }
   218→        _cv.notify_all();
   219→        for (auto& t : _threads) t.join();
   220→    }
   221→
   222→    void enqueue(std::function<void()> job) override
   223→    {
   224→        {
   225→            std::lock_guard lock(_mtx);
   226→            _jobs.push(std::move(job));
   227→        }
   228→        _cv.notify_one();
   229→    }
   230→
   231→private:
   232→    void workerLoop()
   233→    {
   234→        for (;;)
   235→        {
   236→            std::function<void()> job;
   237→            {
   238→                std::unique_lock lock(_mtx);
   239→                _cv.wait(lock, [this] { return _shutdown || !_jobs.empty(); });
   240→                if (_shutdown && _jobs.empty()) return;
   241→                job = std::move(_jobs.front());
   242→                _jobs.pop();
   243→            }
   244→            try { job(); }
   245→            catch (const std::exception& ex)
   246→            {
   247→                std::cerr << "[thread-pool] unhandled job exception → " << ex.what() << '\n';
   248→            }
   249→        }
   250→    }
   251→
   252→    std::mutex                      _mtx;
   253→    std::condition_variable         _cv;
   254→    std::queue<std::function<void()>> _jobs;
   255→    std::vector<std::thread>        _threads;
   256→    bool                            _shutdown;
   257→};
