   411→            if (!docOpt) continue;  // Deleted between index & query
   412→
   413→            const Document& doc = *docOpt;
   414→            std::string snippet =
   415→                buildSnippet(doc.body.empty() ? doc.title : doc.body, parsed.tokens);
