   422→private:
   423→    // Full reindex job
   424→    void performFullReindex()
   425→    {
   426→        _logger->info("Starting FULL re-index");
   427→
   428→        const auto now  = std::chrono::system_clock::now();
   429→        auto        docs = _repository->fetchUpdatedDocuments(_lastFullIndex);
   430→        size_t      processed = 0;
   431→
   432→        for (const auto& doc : docs)
   433→        {
   434→            try
   435→            {
   436→                _backend->put(doc);
   437→                ++processed;
   438→            }
   439→            catch (const std::exception& ex)
   440→            {
   441→                _logger->error(std::string("Indexing failed for doc #") + doc.id + ": " +
   442→                               ex.what());
   443→            }
   444→        }
   445→        _lastFullIndex = now;
   446→        _logger->info("Full re-index finished, processed " + std::to_string(processed) +
   447→                      " document(s)");
   448→    }
   449→
   450→    static std::string buildSnippet(const std::string& text,
   451→                                    const std::vector<std::string>& terms,
   452→                                    std::size_t                      radius = 50)
   453→    {
   454→        if (text.empty()) return {};
   455→
   456→        // Find first occurrence of any term (case-insensitive)
   457→        auto pos = std::string::npos;
   458→        for (const auto& term : terms)
   459→        {
   460→            std::string lcText(text);
   461→            std::transform(lcText.begin(), lcText.end(), lcText.begin(), ::tolower);
   462→            auto p = lcText.find(term);
   463→            if (p != std::string::npos) { pos = std::min(pos, p); }
   464→        }
   465→
   466→        if (pos == std::string::npos) pos = 0;
   467→        std::size_t begin = (pos > radius) ? pos - radius : 0;
   468→        std::size_t end   = std::min(begin + radius * 2, text.size());
   469→
   470→        std::string snippet = text.substr(begin, end - begin);
   471→        if (begin != 0) snippet = "…" + snippet;
   472→        if (end != text.size()) snippet += "…";
   473→
   474→        return QueryParser::highlight(snippet, terms);
   475→    }
