    81→/**
    82→ *  Perform lightweight quoting to protect against SQL injection
    83→ *  when constructing raw SQL fragments.  The ORM still binds the
    84→ *  parameters using prepared statements, but defensive programming
    85→ *  never hurts.
    86→ *
    87→ *  @note This is NOT a full SQL sanitizer.  For production code,
    88→ *        always use parameter binding offered by the underlying
    89→ *        database driver.
    90→ */
    91→inline std::string sql_escape(std::string_view raw)
    92→{
    93→    std::string out;
    94→    out.reserve(raw.size() + 2); // cheap guess
    95→    for (char ch : raw)
    96→    {
    97→        if (ch == '\'' || ch == '\"' || ch == '\\')
    98→            out.push_back('\\');
    99→        out.push_back(ch);
   100→    }
   101→    return out;
   102→}
