   181→    std::vector<std::shared_ptr<Node>> children;
   182→
   183→    BoolNode(BoolOperator op_, std::vector<NodePtr> ch)
   184→        : op(op_), children(std::move(ch)) {}
   185→
   186→    std::string to_sql(std::vector<std::string>& out_params) const override
   187→    {
