   491→    std::shared_ptr<IArticleRepository> m_repo;
   492→
   493→    static void collect_terms_recursive(const NodePtr& node,
   494→                                        std::vector<std::string>& dst)
   495→    {
   496→        if (!node)
   497→            return;
   498→
   499→        if (auto term = std::dynamic_pointer_cast<TermNode>(node))
   500→        {
   501→            dst.push_back(term->token);
   502→            return;
   503→        }
   504→
   505→        if (auto group = std::dynamic_pointer_cast<BoolNode>(node))
   506→        {
   507→            for (auto const& ch : group->children)
