   103→
   104→class Lexer
   105→{
   106→public:
   107→    explicit Lexer(std::string_view input) : m_input(input), m_cursor(0) {}
   108→
   109→    [[nodiscard]] const Token& peek() const { return m_current; }
   110→
   111→    [[nodiscard]] Token next()
   112→    {
   113→        Token t = m_current;
   114→        m_current = lex();
   115→        return t;
   116→    }
   117→
   118→    void consume() { m_current = lex(); }
   119→
   120→    void reset()
   121→    {
   122→        m_cursor  = 0;
   123→        m_current = lex();
   124→    }
   125→
   126→private:
   127→    std::string_view m_input;
   128→    std::size_t      m_cursor;
   129→    Token            m_current { TokenType::EndOfInput, "", 0 };
   130→
   131→    // Skip whitespace but keep track of cursor
   132→    void skip_ws()
   133→    {
   134→        while (m_cursor < m_input.size() && std::isspace(static_cast<unsigned char>(m_input[m_cursor])))
   135→            ++m_cursor;
   136→    }
   137→
   138→    // Read characters while predicate holds
   139→    template <typename Pred>
   140→    std::string read_while(Pred p)
   141→    {
   142→        const auto start = m_cursor;
   143→        while (m_cursor < m_input.size() && p(static_cast<unsigned char>(m_input[m_cursor])))
   144→            ++m_cursor;
   145→        return std::string { m_input.substr(start, m_cursor - start) };
   146→    }
   147→
   148→    Token lex()
   149→    {
   150→        skip_ws();
   151→        if (m_cursor >= m_input.size())
   152→            return { TokenType::EndOfInput, "", m_cursor };
   153→
   154→        const char ch = m_input[m_cursor];
   155→
   156→        // Punctuation tokens
   157→        switch (ch)
   158→        {
   159→            case ':':
   160→                ++m_cursor;
   161→                return { TokenType::Colon, ":", m_cursor - 1 };
   162→            case '(':
   163→                ++m_cursor;
   164→                return { TokenType::LParen, "(", m_cursor - 1 };
   165→            case ')':
   166→                ++m_cursor;
   167→                return { TokenType::RParen, ")", m_cursor - 1 };
   168→            case '"':
   169→                return lex_phrase();
   170→            default:
   171→                break;
   172→        }
   173→
   174→        // Word or reserved keyword
   175→        if (std::isalnum(static_cast<unsigned char>(ch)) || ch == '_' || ch == '-')
   176→        {
   177→            auto word = read_while([](unsigned char c) {
   178→                return std::isalnum(c) || c == '_' || c == '-' || c == '.';
   179→            });
   180→
   181→            const auto lower = to_lower(word);
   182→            if (lower == "and")
   183→                return { TokenType::And, word, m_cursor - word.size() };
   184→            if (lower == "or")
   185→                return { TokenType::Or, word, m_cursor - word.size() };
   186→            if (lower == "not")
   187→                return { TokenType::Not, word, m_cursor - word.size() };
   188→
   189→            return { TokenType::Word, word, m_cursor - word.size() };
   190→        }
   191→
   192→        throw ParseError { std::string { "Invalid character '" } + ch + "'", m_cursor };
   193→    }
   194→
   195→    Token lex_phrase()
   196→    {
   197→        const std::size_t start_pos = m_cursor;
   198→        ++m_cursor; // skip opening quote
   199→
   200→        std::ostringstream oss;
   201→        bool escaped = false;
   202→
   203→        while (m_cursor < m_input.size())
   204→        {
   205→            char ch = m_input[m_cursor++];
   206→            if (escaped)
   207→            {
   208→                // Accept common escape sequences or keep char as is
   209→                switch (ch)
   210→                {
   211→                    case '"':  oss << '"'; break;
   212→                    case '\\': oss << '\\'; break;
   213→                    case 'n':  oss << '\n'; break;
   214→                    case 't':  oss << '\t'; break;
   215→                    default:   oss << ch;  break;
   216→                }
   217→                escaped = false;
   218→            }
   219→            else if (ch == '\\')
   220→            {
   221→                escaped = true;
   222→            }
   223→            else if (ch == '"')
   224→            {
   225→                // End of phrase
   226→                return { TokenType::Phrase, oss.str(), start_pos };
   227→            }
   228→            else
   229→            {
   230→                oss << ch;
   231→            }
   232→        }
   233→
   234→        // Reached end-of-input without closing quote
   235→        throw ParseError { "Unterminated string literal", start_pos };
   236→    }
   237→
   238→    static std::string to_lower(std::string_view sv)
   239→    {
   240→        std::string out;
   241→        out.reserve(sv.size());
   242→        std::transform(sv.begin(), sv.end(), std::back_inserter(out),
   243→                       [](unsigned char c) { return static_cast<char>(std::tolower(c)); });
   244→        return out;
   245→    }
   246→};
