     4→*
     5→*  Component: RBAC (Role-Based Access-Control) Permission Evaluator
     6→*  ---------------------------------------------------------------------
     7→*  This module belongs to the Security / Authorization layer of
     8→*  BlogSuite.  It is responsible for efficiently determining whether a
     9→*  user possesses a specific permission by combining role membership
    10→*  (fetched via Repository) with an in-memory, thread-safe cache that
    11→*  features automatic time-to-live (TTL) expiry.
    12→*
    13→*  NOTE:
    14→*    • This file is self-contained to keep example size reasonable; in
    15→*      production it would be split into separate headers/sources.
    16→*    • Any database access is simulated through an in-memory repository
    17→*      (see `InMemoryRoleRepository`) so the file builds standalone.
    18→*
    19→*  Author : IntraLedger Engineering
    20→*  License: Proprietary, All Rights Reserved
    21→***********************************************************************/
    22→
    23→#include <algorithm>
    24→#include <bitset>
    25→#include <chrono>
    26→#include <cstdint>
    27→#include <cstdlib>
    28→#include <future>
    29→#include <iostream>
    30→#include <memory>
    31→#include <mutex>
    32→#include <shared_mutex>
    33→#include <string>
    34→#include <thread>
    35→#include <unordered_map>
    36→#include <utility>
    37→#include <vector>
    38→
    39→namespace ilbs   /* IntraLedger BlogSuite */
    40→{
    41→namespace rbac   /* Role-Based Access Control */
    42→{
    43→
    44→/* ------------------------------------------------------------------ */
    45→/* 1. Permission Enumeration                                           */
    46→/* ------------------------------------------------------------------ */
    47→
    48→enum class Permission : std::uint16_t
    49→{
    50→    ReadArticle          = 0,
    51→    WriteArticle         = 1,
    52→    PublishArticle       = 2,
    53→    DeleteArticle        = 3,
    54→    ManageUsers          = 4,
    55→    ManageSubscriptions  = 5,
    56→    ViewAnalytics        = 6,
    57→    SystemAdministration = 7,
    58→
    59→    COUNT /* Keep this one last */
    60→};
    61→
    62→constexpr std::size_t kPermissionCount =
    63→    static_cast<std::size_t>(Permission::COUNT);
    64→
    65→/* ------------------------------------------------------------------ */
    66→/* 2. Role Entity                                                      */
    67→/* ------------------------------------------------------------------ */
    68→
    69→struct Role
    70→{
    71→    std::uint32_t      id             = 0;
    72→    std::string        name;
    73→    std::bitset<kPermissionCount> permissions;
    74→};
    75→
    76→/* ------------------------------------------------------------------ */
    77→/* 3. Repository Interface & Mock Implementation                       */
    78→/* ------------------------------------------------------------------ */
    79→
    80→class IUserRoleRepository
    81→{
    82→public:
    83→    virtual ~IUserRoleRepository() = default;
    84→    virtual std::vector<Role> fetchRolesForUser(std::uint32_t userId) = 0;
    85→};
    86→
    87→/*
    88→ * A very small in-memory repository to simulate database calls.
    89→ * Thread-safe and deliberately slow to help verify the cache path.
    90→ */
    91→class InMemoryRoleRepository final : public IUserRoleRepository
    92→{
    93→public:
    94→    InMemoryRoleRepository()
    95→    {
    96→        // --- Seed demo roles ----------------------------------------
    97→        Role author;
    98→        author.id   = 1;
    99→        author.name = "Author";
   100→        author.permissions.set(static_cast<std::size_t>(Permission::ReadArticle));
   101→        author.permissions.set(static_cast<std::size_t>(Permission::WriteArticle));
   102→        author.permissions.set(static_cast<std::size_t>(Permission::PublishArticle));
   103→
   104→        Role admin;
   105→        admin.id   = 2;
   106→        admin.name = "Administrator";
   107→        admin.permissions.set(); // all bits to 1
   108→        admin.permissions.reset(static_cast<std::size_t>(Permission::DeleteArticle)); // Example
   109→
   110→        m_rolesByUser.emplace(1001U, std::vector<Role>{author});
   111→        m_rolesByUser.emplace(  42U, std::vector<Role>{author, admin});
   112→    }
   113→
   114→    std::vector<Role> fetchRolesForUser(std::uint32_t userId) override
   115→    {
   116→        // Simulate I/O latency
   117→        std::this_thread::sleep_for(std::chrono::milliseconds(25));
   118→
   119→        const auto it = m_rolesByUser.find(userId);
   120→        if (it == m_rolesByUser.end())
   121→            return {};
   122→
   123→        return it->second;
   124→    }
   125→
   126→private:
   127→    std::unordered_map<std::uint32_t, std::vector<Role>> m_rolesByUser;
   128→};
   129→
   130→/* ------------------------------------------------------------------ */
   131→/* 4. Permission Evaluator Service                                     */
   132→/* ------------------------------------------------------------------ */
   133→
   134→class PermissionEvaluator
   135→{
   136→public:
   137→    explicit PermissionEvaluator(std::shared_ptr<IUserRoleRepository> repo,
   138→                                 std::chrono::seconds cacheTtl = std::chrono::minutes(2))
   139→        : m_repo(std::move(repo)), m_cacheTtl(cacheTtl)
   140→    {
   141→        if (!m_repo)
   142→            throw std::invalid_argument("IUserRoleRepository cannot be null");
   143→
   144→        // Schedule periodic cache pruning
   145→        m_cleanerThread = std::thread(&PermissionEvaluator::housekeepingWorker, this);
   146→    }
   147→
   148→    ~PermissionEvaluator()
   149→    {
   150→        m_shutdownRequested.store(true);
   151→        if (m_cleanerThread.joinable())
   152→            m_cleanerThread.join();
   153→    }
   154→
   155→    PermissionEvaluator(const PermissionEvaluator&)            = delete;
   156→    PermissionEvaluator& operator=(const PermissionEvaluator&) = delete;
   157→
   158→    /* Evaluate whether the user has `perm`. Fast path hits the cache. */
   159→    bool hasPermission(std::uint32_t userId, Permission perm)
   160→    {
   161→        const CacheKey key{userId, perm};
   162→
   163→        // ---------- 1. Try cache hit (shared lock) -----------------
   164→        {
   165→            std::shared_lock<std::shared_mutex> rLock(m_cacheMutex);
   166→            auto it = m_cache.find(key);
   167→            if (it != m_cache.end() && !isExpired(it->second))
   168→            {
   169→                return it->second.granted;
   170→            }
   171→        }
   172→
   173→        // ---------- 2. Slow path ‑ fetch from repository -----------
   174→        bool granted = false;
   175→        try
   176→        {
   177→            // Launch fetch asynchronously to prevent blocking for too long
   178→            std::future<std::vector<Role>> fut =
   179→                std::async(std::launch::async, &IUserRoleRepository::fetchRolesForUser, m_repo, userId);
   180→
   181→            const std::vector<Role> roles = fut.get();
   182→            granted                       = evaluateRoles(roles, perm);
   183→        }
   184→        catch (const std::exception& ex)
   185→        {
   186→            // Log & fall back to conservative denial; in real code route to logger
   187→            std::cerr << "[RBAC] Repository access failed: " << ex.what() << '\n';
   188→            granted = false;
   189→        }
   190→
   191→        // ---------- 3. Store in cache (unique lock) ----------------
   192→        {
   193→            std::unique_lock<std::shared_mutex> wLock(m_cacheMutex);
   194→            m_cache[key] = CacheEntry{granted, std::chrono::steady_clock::now()};
   195→        }
   196→
   197→        return granted;
   198→    }
   199→
   200→    /* Explicitly invalidate all cached permissions for a user. */
   201→    void invalidateUser(std::uint32_t userId)
   202→    {
   203→        std::unique_lock<std::shared_mutex> wLock(m_cacheMutex);
   204→        for (auto it = m_cache.begin(); it != m_cache.end();)
   205→        {
   206→            if (it->first.userId == userId)
   207→                it = m_cache.erase(it);
   208→            else
   209→                ++it;
   210→        }
   211→    }
   212→
   213→private:
   214→    /* --------------------- Internal Structures ------------------- */
   215→
   216→    struct CacheKey
   217→    {
   218→        std::uint32_t userId;
   219→        Permission    permission;
   220→
   221→        bool operator==(const CacheKey& other) const noexcept
   222→        {
   223→            return userId == other.userId && permission == other.permission;
   224→        }
   225→    };
   226→
   227→    struct CacheKeyHasher
   228→    {
   229→        std::size_t operator()(const CacheKey& k) const noexcept
   230→        {
   231→            return (static_cast<std::size_t>(k.userId) << 8) ^
   232→                   static_cast<std::size_t>(k.permission);
   233→        }
   234→    };
   235→
   236→    struct CacheEntry
   237→    {
   238→        bool granted;
   239→        std::chrono::steady_clock::time_point ts;
   240→    };
   241→
   242→    /* --------------------- Helper Utilities ---------------------- */
   243→
   244→    static bool evaluateRoles(const std::vector<Role>& roles, Permission perm)
   245→    {
   246→        const std::size_t index = static_cast<std::size_t>(perm);
   247→        return std::any_of(roles.begin(), roles.end(),
   248→                           [index](const Role& r) { return r.permissions.test(index); });
   249→    }
   250→
   251→    bool isExpired(const CacheEntry& e) const noexcept
   252→    {
   253→        return (std::chrono::steady_clock::now() - e.ts) > m_cacheTtl;
   254→    }
   255→
   256→    void housekeepingWorker()
   257→    {
   258→        using namespace std::chrono_literals;
   259→        while (!m_shutdownRequested.load())
   260→        {
   261→            {
   262→                std::unique_lock<std::shared_mutex> wLock(m_cacheMutex);
   263→                for (auto it = m_cache.begin(); it != m_cache.end();)
   264→                {
   265→                    if (isExpired(it->second))
   266→                        it = m_cache.erase(it);
   267→                    else
   268→                        ++it;
   269→                }
   270→            }
   271→            std::this_thread::sleep_for(15s);
   272→        }
   273→    }
   274→
   275→    /* --------------------- Data Members -------------------------- */
   276→
   277→    std::shared_ptr<IUserRoleRepository> m_repo;
   278→    std::chrono::seconds                 m_cacheTtl;
   279→
   280→    std::unordered_map<CacheKey, CacheEntry, CacheKeyHasher> m_cache;
   281→    mutable std::shared_mutex                                  m_cacheMutex;
   282→
   283→    std::thread                     m_cleanerThread;
   284→    std::atomic_bool                m_shutdownRequested{false};
   285→};
   286→
   287→/* ------------------------------------------------------------------ */
   288→/* 5. Stand-Alone Test Harness                                         */
   289→/* ------------------------------------------------------------------ */
   290→
   291→#if defined(ILBS_RBAC_UNIT_TEST)
   292→/*
   293→ * A quick single-threaded functional check. Compile with:
   294→ *   g++ -std=c++20 -DILBS_RBAC_UNIT_TEST module_39.cpp -lpthread
   295→ */
   296→int main()
   297→{
   298→    using namespace ilbs::rbac;
   299→
   300→    auto repo     = std::make_shared<InMemoryRoleRepository>();
   301→    PermissionEvaluator evaluator(repo, std::chrono::seconds(10));
   302→
   303→    const std::uint32_t user = 1001;
   304→
   305→    std::cout << "User " << user << " may publish? "
   306→              << evaluator.hasPermission(user, Permission::PublishArticle) << '\n';
   307→
   308→    std::cout << "User " << user << " may delete?  "
   309→              << evaluator.hasPermission(user, Permission::DeleteArticle) << '\n';
   310→
   311→    // Invalidate and recheck (should force repo fetch again)
   312→    evaluator.invalidateUser(user);
   313→
   314→    std::cout << "After invalidation: may publish? "
   315→              << evaluator.hasPermission(user, Permission::PublishArticle) << '\n';
   316→
   317→    return EXIT_SUCCESS;
   318→}
   319→#endif /* ILBS_RBAC_UNIT_TEST */
   320→
   321→} // namespace rbac
   322→} // namespace ilbs
   323→```

