    83→    std::string action; // e.g. "read", "edit", "delete"
    84→
    85→    bool operator==(const PermissionKey& rhs) const noexcept
    86→    {
    87→        return userId == rhs.userId &&
    88→               resourceId == rhs.resourceId &&
    89→               action == rhs.action;
    90→    }
    91→};
    92→
    93→struct PermissionKeyHasher
    94→{
    95→    std::size_t operator()(const PermissionKey& k) const noexcept
    96→    {
    97→        std::hash<std::string> h;
    98→        return (h(k.userId) ^ (h(k.resourceId) << 1)) ^ (h(k.action) << 2);
    99→    }
   100→};
   101→
   102→// ---------------------------------------------------------------------------
   103→// LRU Cache (thread-safe)
   104→// ---------------------------------------------------------------------------
   105→template <typename Key, typename Value, typename Hasher = std::hash<Key>>
   106→class LRUCache
   107→{
   108→public:
   109→    explicit LRUCache(std::size_t capacity)
   110→        : m_capacity(capacity)
   111→    {
   112→        if (capacity == 0)
   113→            throw std::invalid_argument("LRUCache capacity must be > 0");
   114→    }
   115→
   116→    std::optional<Value> get(const Key& key)
   117→    {
   118→        std::unique_lock lock(m_mutex);
   119→        auto it = m_map.find(key);
   120→        if (it == m_map.end()) return std::nullopt;
   121→
   122→        // Move accessed element to front (most-recent)
   123→        m_list.splice(m_list.begin(), m_list, it->second);
   124→        return it->second->second;
   125→    }
   126→
   127→    void put(const Key& key, const Value& value)
   128→    {
   129→        std::unique_lock lock(m_mutex);
   130→
   131→        auto it = m_map.find(key);
   132→        if (it != m_map.end())
   133→        {
   134→            // Override existing entry
   135→            it->second->second = value;
   136→            m_list.splice(m_list.begin(), m_list, it->second);
   137→            return;
   138→        }
   139→
   140→        // Insert new entry
   141→        m_list.emplace_front(key, value);
   142→        m_map[key] = m_list.begin();
   143→
   144→        // Evict if needed
   145→        if (m_map.size() > m_capacity)
   146→        {
   147→            auto last = m_list.end();
   148→            --last;
   149→            m_map.erase(last->first);
   150→            m_list.pop_back();
   151→        }
   152→    }
   153→
   154→private:
   155→    using ListType = std::list<std::pair<Key, Value>>;
   156→
   157→    std::size_t                         m_capacity;
   158→    ListType                            m_list;
   159→    std::unordered_map<Key,
   160→                       typename ListType::iterator,
   161→                       Hasher>          m_map;
   162→    mutable std::shared_mutex           m_mutex;
   163→};
   164→
   165→// ---------------------------------------------------------------------------
   166→// Voter Interfaces
   167→// ---------------------------------------------------------------------------
   168→class IAccessVoter
   169→{
   170→public:
   171→    virtual ~IAccessVoter() = default;
   172→
   173→    /*
   174→     * Return true if this voter grants permission for the action on
   175→     * the resource by the given user. A voter that is not applicable
   176→     * should return std::nullopt.
   177→     */
   178→    virtual std::optional<bool>
   179→    vote(const UserContext&       user,
   180→         const ResourceDescriptor res,
   181→         std::string_view         action) const = 0;
   182→
   183→protected:
   184→    // helper for inheritors
   185→    static bool roleIn(const UserContext& user, Role r)
   186→    {
   187→        return user.hasRole(r);
   188→    }
   189→};
   190→
   191→// ---------------------------------------------------------------------------
   192→// Concrete Voters
   193→// ---------------------------------------------------------------------------
   194→
   195→// 1. Role-based voter --------------------------------------------------------
   196→class RoleVoter final : public IAccessVoter
   197→{
   198→public:
   199→    std::optional<bool>
   200→    vote(const UserContext& user,
   201→         const ResourceDescriptor /*res*/,
   202→         std::string_view action) const override
   203→    {
   204→        if (action == "admin")
   205→        {
   206→            // Only admins may perform "admin" actions
   207→            return roleIn(user, Role::Admin) || roleIn(user, Role::SuperAdmin);
   208→        }
   209→
   210→        // Non-admin actions are not this voter's responsibility
   211→        return std::nullopt;
   212→    }
   213→};
   214→
   215→// 2. Ownership voter ---------------------------------------------------------
   216→class OwnershipVoter final : public IAccessVoter
   217→{
   218→public:
   219→    std::optional<bool>
   220→    vote(const UserContext& user,
   221→         const ResourceDescriptor res,
   222→         std::string_view action) const override
   223→    {
   224→        if (action == "edit" || action == "delete")
   225→        {
   226→            return res.ownerId == user.id || roleIn(user, Role::Editor) || roleIn(user, Role::SuperAdmin);
   227→        }
   228→
   229→        return std::nullopt;
   230→    }
   231→};
   232→
   233→// 3. Visibility / subscription voter ----------------------------------------
   234→class VisibilityVoter final : public IAccessVoter
   235→{
   236→public:
   237→    std::optional<bool>
   238→    vote(const UserContext& user,
   239→         const ResourceDescriptor res,
   240→         std::string_view action) const override
   241→    {
   242→        if (action != "read")
   243→            return std::nullopt;
   244→
   245→        if (res.isPublic) return true;
   246→        if (!user.authenticated) return false;
   247→
   248→        // Pretend a repository call that certifies premium subscription.
   249→        // We replace it with simple role check for demo purposes.
   250→        return res.isPremium ? roleIn(user, Role::Reader) || roleIn(user, Role::Author) ||
   251→                                   roleIn(user, Role::Editor) || roleIn(user, Role::Admin) ||
   252→                                   roleIn(user, Role::SuperAdmin)
   253→                             : true;
   254→    }
   255→};
   256→
   257→// ---------------------------------------------------------------------------
   258→// Permission Service (Affirmative-Based Decision Manager)
   259→// ---------------------------------------------------------------------------
   260→class PermissionService
   261→{
   262→public:
   263→    // Dependency injection (repositories, config, etc.)
   264→    struct Dependencies
   265→    {
   266→        std::shared_ptr<IUserRepository>        userRepo;
   267→        std::shared_ptr<IArticleRepository>     articleRepo;
   268→        std::shared_ptr<ISubscriptionRepository> subscriptionRepo;
   269→    };
   270→
   271→    explicit PermissionService(Dependencies deps,
   272→                               std::size_t    cacheSize = 4'096)
   273→        : m_deps(std::move(deps))
   274→        , m_cache(cacheSize)
   275→    {
   276→        // Register built-in voters
   277→        m_voters.emplace_back(std::make_unique<RoleVoter>());
   278→        m_voters.emplace_back(std::make_unique<OwnershipVoter>());
   279→        m_voters.emplace_back(std::make_unique<VisibilityVoter>());
   280→    }
   281→
   282→    /*
   283→     * Evaluate permission for a user/action/resource triple.
   284→     * An "affirmative" strategy is used: the first voter that
   285→     * returns true grants access, while explicit false denies.
   286→     * If no voter returns a result, deny by default.
   287→     */
   288→    bool hasPermission(const UserContext& user,
   289→                       const ResourceDescriptor& resource,
   290→                       std::string_view action)
   291→    {
   292→        // Check cache
   293→        PermissionKey key{user.id, resource.ownerId /* acts as resourceId */, std::string(action)};
   294→        if (auto cached = m_cache.get(key))
   295→            return *cached;
   296→
   297→        bool result = evaluate(user, resource, action);
   298→
   299→        // Store in cache
   300→        m_cache.put(key, result);
   301→        return result;
   302→    }
   303→
   304→private:
   305→    bool evaluate(const UserContext& user,
   306→                  const ResourceDescriptor& resource,
   307→                  std::string_view action) const
   308→    {
   309→        // SuperAdmin shortcut
   310→        if (user.hasRole(Role::SuperAdmin))
   311→            return true;
   312→
   313→        // Delegating to voters
   314→        for (const auto& voter : m_voters)
   315→        {
   316→            try
   317→            {
   318→                std::optional<bool> voteResult = voter->vote(user, resource, action);
   319→
   320→                if (!voteResult.has_value())
   321→                    continue; // abstain ‑> next voter
   322→
   323→                if (*voteResult)
   324→                    return true;  // grant immediately
   325→
   326→                // deny overrides all
   327→                return false;
   328→            }
   329→            catch (const std::exception& e)
   330→            {
   331→                // Defensive: log & move on to next voter
   332→                std::cerr << "[security] Voter exception: " << e.what() << '\n';
   333→            }
   334→        }
   335→
   336→        // No voter granted access, deny by default
   337→        return false;
   338→    }
   339→
   340→    Dependencies                                     m_deps;
   341→    std::vector<std::unique_ptr<IAccessVoter>>       m_voters;
   342→    LRUCache<PermissionKey, bool, PermissionKeyHasher> m_cache;
   343→};
   344→
