   346→// Simple inline unit test (can be excluded in production builds)
   347→// ---------------------------------------------------------------------------
   348→#ifdef BLOGSUITE_SECURITY_SELFTEST
   349→#include <cassert>
   350→
   351→static void selfTest()
   352→{
   353→    PermissionService::Dependencies deps{/*nullptr, nullptr, nullptr*/};
   354→    PermissionService svc(deps, 32);
   355→
   356→    UserContext alice { "alice", {Role::Author}, true };
   357→    UserContext bob   { "bob",   {Role::Reader}, true };
   358→    UserContext admin { "admin", {Role::Admin},  true };
   359→
   360→    ResourceDescriptor pubArticle  { "alice", true,  false };
   361→    ResourceDescriptor privArticle { "alice", false, true  };
   362→
   363→    // Public read
   364→    assert( svc.hasPermission(bob, pubArticle, "read") );
   365→
   366→    // Private read w/o subscription -> deny
   367→    assert( !svc.hasPermission(bob, privArticle, "read") );
   368→
   369→    // Owner can edit
   370→    assert( svc.hasPermission(alice, pubArticle, "edit") );
   371→
   372→    // Non-owner cannot delete
   373→    assert( !svc.hasPermission(bob, pubArticle, "delete") );
   374→
   375→    // Admin can admin
   376→    assert( svc.hasPermission(admin, pubArticle, "admin") );
   377→
   378→    // Cache hit (repeat query)
   379→    assert( svc.hasPermission(admin, pubArticle, "admin") );
   380→}
   381→
   382→static int _ = (selfTest(), 0);
   383→#endif // BLOGSUITE_SECURITY_SELFTEST
   384→
   385→} // namespace intraledger::blogsuite::security
