    53→class ScopedMetricTimer final
    54→{
    55→public:
    56→    explicit ScopedMetricTimer(std::string_view metricName) noexcept
    57→        : m_metricName(metricName),
    58→          m_start(std::chrono::steady_clock::now())
    59→    {}
    60→
    61→    // Not copyable / movable
    62→    ScopedMetricTimer(const ScopedMetricTimer&) = delete;
    63→    ScopedMetricTimer& operator=(const ScopedMetricTimer&) = delete;
    64→    ScopedMetricTimer(ScopedMetricTimer&&)            = delete;
    65→    ScopedMetricTimer& operator=(ScopedMetricTimer&&) = delete;
    66→
    67→    ~ScopedMetricTimer() noexcept
    68→    {
    69→        using namespace std::chrono;
    70→        const auto duration = duration_cast<milliseconds>(
    71→                                  steady_clock::now() - m_start)
    72→                                  .count();
    73→
    74→        // Push to central metrics collector (here we just log)
    75→        spdlog::trace("[METRIC] {} = {} ms", m_metricName, duration);
    76→    }
    77→
    78→private:
    79→    std::string m_metricName;
    80→    std::chrono::steady_clock::time_point m_start;
