     * @param userId User identifier
     * @param action Action being performed (e.g., "edit", "delete")
     * @param resourceId Target resource identifier
     * @return true if permitted
     */
    virtual bool hasPermission(
        const std::string& userId,
        std::string_view action,
        const std::string& resourceId) = 0;

    // ===== Rate Limiting =====

    /**
     * Check if a login attempt is allowed (not rate limited).
     * @param identifier IP address or user identifier
     * @return true if attempt should proceed
     */
    virtual bool isLoginAttemptAllowed(const std::string& identifier) = 0;

